import { useCreatePostFolderMutation } from "~/redux/api/post__premium_only";
import { useEffect, useRef, useState } from "@wordpress/element";
import { useCustomAlert } from "~/components/alert/Alert";
import CreateFolder from "~/shared/actions/CreateFolder";
import { Theme } from "~/types/settings/settings";
import { Folder } from "~/types/folder";
import usePost from "../hooks/usePost";
import { __ } from "@wordpress/i18n";

const Create = ({
    theme = "default",
    nested,
    setFolder,
}: {
    theme?: Theme;
    nested?: boolean;
    setFolder?: (folder: Folder) => void;
}) => {
    const [folderName, setFolderName] = useState<string>(
        __("New folder", "ninja-media"),
    );
    const inputRef = useRef<HTMLInputElement | null>(null);
    const [loading, setLoading] = useState<boolean>(false);
    const [createFolder] = useCreatePostFolderMutation();

    const { showAlert } = useCustomAlert();

    const { setPost, activeFolder } = usePost();

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    const handleCreate = async () => {
        try {
            setLoading(true);

            const response = await createFolder({
                postType: pnpnm?.currentPostType,
                name: folderName || __("New folder", "ninja-media"),
                parentId: activeFolder?.id,
            }).unwrap();

            if (response?.data) {
                setFolder?.(response?.data ?? []);
            }

            setFolderName(__("New folder", "ninja-media"));

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Folder created successfully", "ninja-media"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __("Failed to create folder", "ninja-media"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } finally {
            setLoading(false);
            setPost("createFolder", { create: false });
        }
    };

    return (
        <CreateFolder
            theme={theme}
            nested={nested}
            inputRef={inputRef}
            folderName={folderName}
            setFolderName={setFolderName}
            onCreate={handleCreate}
            onCancel={() => setPost("createFolder", { create: false })}
            loading={loading}
        />
    );
};

export default Create;
