import { useDragContext } from "~/shared/context/DragContext";
import { MenuItem } from "~/types/post__premium_only/post";
import ThemeIcon from "~/shared/folder/ThemeIcon";
import Folder from "~/shared/folder/Folder";
import Status from "~/components/status";

const Favorites = ({
    enabled,
    menu,
    theme,
    showCount,
    count,
    onMenu,
    onMouseEnter,
}: MenuItem) => {
    const { isDragging, hoveredFolderId } = useDragContext();

    const isHovering = isDragging && hoveredFolderId === "favorites";

    if (!enabled) return null;

    return (
        <Status
            isPro={true}
            size="extrasmall"
            placement="right-center"
            right={3}
        >
            <div data-folder-id="favorites">
                <Folder
                    name="Favorites"
                    count={showCount ? count : undefined}
                    icon={
                        <ThemeIcon
                            theme={theme}
                            active={menu === "favorites"}
                            open={menu === "favorites"}
                        />
                    }
                    active={menu === "favorites"}
                    open={menu === "favorites"}
                    drop={isHovering}
                    onClick={() => {
                        if (!pnpnm?.isPro) return;

                        onMenu("favorites");
                    }}
                    onMouseEnter={onMouseEnter}
                />
            </div>
        </Status>
    );
};

export default Favorites;
