import { TABLE_ADAPTERS } from "~/shared/context/tableAdapters";
import { useCustomAlert } from "~/components/alert/Alert";
import { useAppDispatch } from "~/redux/hooks";
import { store } from "~/redux/store";
import usePost from "./usePost";
import {
    removeFolder,
    setFolders,
    updateFolder,
} from "~/redux/features/post__premium_only/post";
import {
    useAssignPostMutation,
    useFavoritePostMutation,
    useMovePostFolderMutation,
    useUpdatePostFolderMutation,
} from "~/redux/api/post__premium_only";

const usePostActions = () => {
    const { setPost, menu, folders, cutFolders } = usePost();
    const [updatePostFolderMutation] = useUpdatePostFolderMutation();
    const [movePostFolderMutation] = useMovePostFolderMutation();
    const [assignPostMutation] = useAssignPostMutation();
    const [favoritePostMutation] = useFavoritePostMutation();

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    const colorUpdate = async (id: string | number, color: string | null) => {
        try {
            await updatePostFolderMutation({ id, color }).unwrap();
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to update folder color",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const moveFolder = async ({
        target,
        drop,
        dragged,
        folderId,
    }: {
        target: string | number;
        drop?: boolean;
        dragged?: string | number;
        folderId?: string | number;
    }) => {
        const ids = drop
            ? [dragged as string | number]
            : cutFolders?.folders?.map((folder) => folder.id) ?? [];

        const foldersToMove = drop
            ? Object.values(folders)
                  .flat()
                  .filter((f) => String(f.id) === String(dragged))
            : cutFolders?.folders ?? [];

        const finalId = target === "root" ? "root" : target;

        try {
            const response = await movePostFolderMutation({
                id: finalId,
                ids,
            }).unwrap();

            dispatch(removeFolder(ids));

            const currentChildren =
                store.getState().post.folders[finalId] ?? [];

            let updatedChildren = currentChildren;

            if (drop && folderId && finalId === "root") {
                const targetIndex = currentChildren.findIndex(
                    (f) => String(f.id) === String(folderId),
                );

                if (targetIndex === -1) {
                    updatedChildren = [...currentChildren, ...foldersToMove];
                } else {
                    updatedChildren = [
                        ...currentChildren.slice(0, targetIndex),
                        ...foldersToMove,
                        ...currentChildren.slice(targetIndex),
                    ];
                }
            } else {
                updatedChildren = [...foldersToMove, ...currentChildren];
            }

            dispatch(
                setFolders({
                    id: finalId,
                    children: updatedChildren,
                }),
            );

            setPost("cutFolders", { cut: false, folders: [] });
            setPost("moveFolder", { move: false, id: null });

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    (drop
                        ? "Folder moved successfully"
                        : `${
                              ids.length > 1
                                  ? `${ids.length} folders`
                                  : "1 folder"
                          } cut successfully`),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            setPost("moveFolder", { move: false, id: null });

            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    (drop ? "Failed to move folder" : "Failed to cut folder"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const assignPost = async (
        id: string | number,
        posts: (number | string)[],
    ) => {
        try {
            const response = await assignPostMutation({
                id,
                posts,
            }).unwrap();

            // forceDisableBulkSelect();

            dispatch(
                updateFolder({
                    id: id,
                    data: {
                        attachmentCount: Number(response?.data?.total) ?? 0,
                    },
                }),
            );

            dispatch(
                updateFolder({
                    id: response?.data?.previousFolder?.id!,
                    data: {
                        attachmentCount:
                            Number(response?.data?.previousFolder?.remaining) ??
                            0,
                    },
                }),
            );

            setPost("uncategorized", response?.data?.uncategorizedCount ?? 0);

            if (
                response?.data?.previousFolder?.id ||
                menu === "uncategorized"
            ) {
                response?.data?.assigned?.forEach((postId) => {
                    TABLE_ADAPTERS.forEach((adapter) =>
                        adapter.removeRow(Number(postId)),
                    );
                });
            }

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    `${
                        posts.length > 1 ? `${posts.length} posts` : "1 post"
                    } assigned successfully`,
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to assign post(s)",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const favoritePost = async (ids: (string | number)[], favorite = true) => {
        try {
            const response = await favoritePostMutation({
                postType: pnpnm?.currentPostType,
                ids,
                favorite,
            }).unwrap();

            setPost("favorites", response?.data?.favorites ?? 0);

            showAlert({
                toast: true,
                type: "success",
                text: response?.message || "Post(s) added to favorites",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    "Failed to add post(s) to favorites",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    return {
        colorUpdate,
        moveFolder,
        assignPost,
        favoritePost,
    };
};

export default usePostActions;
