import useDisabled from "~/post-types__premium_only/hooks/useDisabled";
import usePost from "~/post-types__premium_only/hooks/usePost";
import InlineStack from "~/components/inlineStack";
import Button from "~/components/button";
import Logo from "~/components/logo";

const Header = () => {
    const { setPost, createFolder, bulkSelect } = usePost();

    const { newFolderDisabled } = useDisabled();

    return (
        <InlineStack align="between" gap={10} wrap={false}>
            <Logo />

            {bulkSelect || createFolder?.create ? (
                <Button
                    variant="secondary"
                    size="extrasmall"
                    rounded="xs"
                    startIcon="cancel"
                    onClick={() => {
                        if (bulkSelect) {
                            setPost("bulkSelect", false);
                            setPost("selectedFolders", []);
                        }
                        if (createFolder?.create) {
                            setPost("createFolder", { create: false });
                        }
                    }}
                >
                    Cancel
                </Button>
            ) : (
                <Button
                    variant="primary"
                    size="extrasmall"
                    rounded="xs"
                    startIcon="create_new_folder"
                    onClick={() =>
                        setPost("createFolder", {
                            create: !createFolder?.create,
                        })
                    }
                    disabled={newFolderDisabled}
                >
                    New Folder
                </Button>
            )}
        </InlineStack>
    );
};

export default Header;
