import { useDeleteFolder } from "~/post-types__premium_only/actions/Delete";
import useDisabled from "~/post-types__premium_only/hooks/useDisabled";
import usePost from "~/post-types__premium_only/hooks/usePost";
import InlineStack from "~/components/inlineStack";
import Sorting from "~/shared/topbar/Sorting";
import Button from "~/components/button";
import More from "~/shared/topbar/More";
import Card from "~/components/card";

const Controls = () => {
    const {
        setPost,
        activeFolder,
        renameFolder,
        folderSorting,
        postSorting,
        order,
        bulkSelect,
        expandAll,
    } = usePost();

    const { openDeleteFolder } = useDeleteFolder();

    const {
        renameFolderDisabled,
        deleteFolderDisabled,
        sortingDisabled,
        moreOptionsDisabled,
    } = useDisabled();

    return (
        <Card
            marginTop={20}
            padding={5}
            background="white"
            rounded="sm"
            border="light"
            flex
            direction="row"
            align="between"
            gap={5}
            wrap={false}
        >
            <InlineStack gap={5} wrap={false}>
                <Button
                    variant="primary"
                    size="extrasmall"
                    rounded="xs"
                    startIcon="edit_document"
                    onClick={() =>
                        setPost("renameFolder", {
                            rename: !renameFolder?.rename,
                            folder: activeFolder,
                        })
                    }
                    disabled={renameFolderDisabled}
                >
                    Rename
                </Button>

                <Button
                    variant="error"
                    size="extrasmall"
                    rounded="xs"
                    startIcon="delete"
                    onClick={() => openDeleteFolder(String(activeFolder?.id))}
                    disabled={deleteFolderDisabled}
                >
                    Delete
                </Button>
            </InlineStack>

            <InlineStack gap={5} wrap={false}>
                <Sorting
                    variant="post"
                    folderSorting={folderSorting}
                    fileSorting={postSorting}
                    order={order}
                    onFolderSorting={(sorting) =>
                        setPost("folderSorting", sorting)
                    }
                    onFileSorting={(sorting) => setPost("postSorting", sorting)}
                    onOrder={(order) => setPost("order", order)}
                    disabled={sortingDisabled}
                />

                <More
                    bulkSelect={bulkSelect}
                    expandAll={expandAll}
                    onSelectedFolders={() => setPost("selectedFolders", [])}
                    onBulkSelect={(value) => setPost("bulkSelect", value)}
                    onExpandAll={(value) => setPost("expandAll", value)}
                    disabled={moreOptionsDisabled}
                />
            </InlineStack>
        </Card>
    );
};

export default Controls;
