import { Attachment } from "~/types/post__premium_only/post";
import usePostActions from "./usePostActions";

type FolderDropParams = {
    targetId: string | number;
    draggedId: string | number;
};

type FileDropParams = {
    id: string | number;
    attachments: Attachment[];
};

type RootDropParams = {
    targetId: string | number;
    draggedId: string | number;
    folderId: string | number;
};

const useDrop = () => {
    const { moveFolder, assignPost, favoritePost } = usePostActions();

    const handleFolderDrop = ({ targetId, draggedId }: FolderDropParams) => {
        moveFolder({
            target: targetId,
            drop: true,
            dragged: draggedId,
        });
    };

    const handleFileDrop = ({ id, attachments }: FileDropParams) => {
        const ids = attachments?.map((attachment) => attachment?.id) ?? [];

        if (id === "favorites") {
            favoritePost(ids);
            return;
        }

        assignPost(id, ids);
    };

    const handleRootDrop = ({
        targetId,
        draggedId,
        folderId,
    }: RootDropParams) => {
        moveFolder({
            target: targetId,
            drop: true,
            dragged: draggedId,
            folderId: folderId,
        });
    };

    return { handleFolderDrop, handleFileDrop, handleRootDrop };
};

export default useDrop;
