import DefaultOpen from "~/assets/icons/folder/DefaultOpen";
import Default from "~/assets/icons/folder/NinjaDefault";
import { Theme } from "~/types/settings/settings";
import { useMemo } from "@wordpress/element";
/* <fs_premium_only> */
import BoldOpen from "~/assets/icons/folder/BoldOpen";
import Awesome from "~/assets/icons/folder/Awesome";
import Bold from "~/assets/icons/folder/Bold";
/* </fs_premium_only> */

const ThemeIcon = ({
    theme,
    open,
    color,
    active,
    drop,
}: {
    theme?: Theme;
    open?: boolean;
    color?: string | null;
    active?: boolean;
    drop?: boolean;
}) => {
    const iconElement = useMemo(() => {
        /* <fs_premium_only> */
        if (theme === "bold")
            return open ? <BoldOpen color={color} /> : <Bold color={color} />;
        if (theme === "awesome") return <Awesome color={color} />;
        if (theme === "plugininja")
            return <Default color={color} active={false} />;
        /* </fs_premium_only> */
        if (drop) return <DefaultOpen color={color} active={active ?? false} />;
        return open ? (
            <DefaultOpen color={color} active={active ?? false} />
        ) : (
            <Default color={color} active={active ?? false} />
        );
    }, [theme, open, color, active, drop]);

    return iconElement;
};

export default ThemeIcon;
