import { Folder, FolderContextMenu } from "~/types/folder";
import { useDuplicateFolder } from "../actions/Duplicate";
import { useDeleteFolder } from "../actions/Delete";
import usePostActions from "./usePostActions";
import usePost from "./usePost";

type HandleFolderContextParams = {
    key: FolderContextMenu;
    folders: Folder[];
};

const useFolderContext = () => {
    const { setPost, bulkSelect } = usePost();

    const { moveFolder } = usePostActions();

    const { openDuplicateFolder } = useDuplicateFolder();

    const { openDeleteFolder } = useDeleteFolder();

    const handleFolderContext = ({
        key,
        folders,
    }: HandleFolderContextParams) => {
        const folder = folders[0];

        switch (key) {
            case "new":
                setPost("activeFolder", folder);
                setPost("createFolder", { create: true, folder });
                return;
            case "color":
                return;
            case "rename":
                setPost("renameFolder", { rename: true, folder });
                return;
            case "cut":
                setPost("cutFolders", { cut: true, folders });

                if (bulkSelect) {
                    setPost("bulkSelect", false);
                    setPost("selectedFolders", []);
                }
                return;
            case "paste":
                setPost("moveFolder", { move: true, id: folder?.id });
                moveFolder({
                    target: folder?.id,
                });
                return;
            case "duplicate":
                if (!pnpnm?.isPro) return;

                openDuplicateFolder(
                    String(folder?.parentId),
                    String(folder?.id),
                );
                return;
            case "download":
                return;
            case "delete":
                openDeleteFolder(String(folder?.id));
                return;
            default: {
                const exhaustiveCheck: never = key;
                return exhaustiveCheck;
            }
        }
    };

    return handleFolderContext;
};

export default useFolderContext;
